-- Source rows in CSV  : 6,694 line items across 6,689 unique COs
-- Imported here       : 6,681 COs (matched to jobs via bt_job_id)
-- Skipped (orphans)   : 8 COs (jobsite still not in jobs table)
-- Status mapping      : Approved → 'sold' (2,627); else → 'pending' (4,054)
-- Dollars imported    : $10,772,423.16
-- Idempotent: existing COs (matched on bt_change_order_id) are skipped.
-- ============================================================

BEGIN;

-- 1. Idempotency column (no-op if it already exists from prior run)
ALTER TABLE bids ADD COLUMN IF NOT EXISTS bt_change_order_id BIGINT;
CREATE UNIQUE INDEX IF NOT EXISTS bids_bt_change_order_id_idx
  ON bids(bt_change_order_id) WHERE bt_change_order_id IS NOT NULL;

-- 2. Stage CO data
CREATE TEMP TABLE bt_co_staging (
  bt_co_id        BIGINT       PRIMARY KEY,
  bt_job_id       BIGINT       NOT NULL,
  custom_co_id    TEXT,
  title           TEXT         NOT NULL,
  description     TEXT,
  notes           TEXT,
  owner_price     NUMERIC(14,2) NOT NULL,
  status_target   TEXT         NOT NULL,
  date_submitted  DATE,
  created_at      TIMESTAMPTZ
) ON COMMIT DROP;

