-- 3. Process: insert estimate + bid per CO
DO $$
DECLARE
  rec          RECORD;
  v_job_id     UUID;
  v_job_client TEXT;
  v_est_id     UUID;
  v_imported   INT := 0;
  v_dup        INT := 0;
  v_no_job     INT := 0;
BEGIN
  FOR rec IN SELECT * FROM bt_co_staging LOOP
    IF EXISTS (SELECT 1 FROM bids WHERE bt_change_order_id = rec.bt_co_id) THEN
      v_dup := v_dup + 1;
      CONTINUE;
    END IF;

    SELECT id, COALESCE(client_name, '') INTO v_job_id, v_job_client
      FROM jobs WHERE bt_job_id = rec.bt_job_id LIMIT 1;

    IF v_job_id IS NULL THEN
      v_no_job := v_no_job + 1;
      CONTINUE;
    END IF;

    INSERT INTO estimates (estimate_name, client_name, status, notes, created_at)
    VALUES (
      rec.title,
      v_job_client,
      CASE WHEN rec.status_target = 'sold' THEN 'approved' ELSE 'draft' END,
      rec.description,
      COALESCE(rec.created_at, NOW())
    )
    RETURNING id INTO v_est_id;

    INSERT INTO bids (
      bt_change_order_id, record_type, linked_job_id, co_name, co_type,
      client_name, bid_amount, gross_profit, gpmd, date_submitted, status,
      estimate_id, notes, projects
    ) VALUES (
      rec.bt_co_id, 'change_order', v_job_id, rec.title, NULL,
      v_job_client, rec.owner_price, 0, 0,
      COALESCE(rec.date_submitted, CURRENT_DATE),
      rec.status_target,
      v_est_id,
      COALESCE(NULLIF(rec.notes, ''), rec.description),
      ''
    );

    v_imported := v_imported + 1;
  END LOOP;

  RAISE NOTICE 'BT CO import complete — Imported: %, Already-imported (skipped): %, No matching job (skipped): %',
    v_imported, v_dup, v_no_job;
END
$$;

COMMIT;
